// Emits one MQTT-style 3-element JSON array per device per tick.
// State per IMEI evolves: load fluctuates, occasional spikes.

const env_data = env.get('Devices');
if (!env_data || !env_data.data) {
    node.error('Devices env var not set');
    return null;
}
const devices = env_data.data;

function initState() {
    return {
        loadFactor: 0.45 + Math.random() * 0.4,
        loadTrend: (Math.random() - 0.5) * 0.005,
        tick: 0,
        netE: 100000 + Math.random() * 500000,
    };
}

function evolve(state) {
    state.tick++;
    state.loadTrend += (Math.random() - 0.5) * 0.002;
    state.loadTrend = Math.max(-0.01, Math.min(0.01, state.loadTrend));
    state.loadFactor += state.loadTrend;
    state.loadFactor += (0.6 - state.loadFactor) * 0.02;
    state.loadFactor = Math.max(0.2, Math.min(1.05, state.loadFactor));
    if (Math.random() < 0.01) state.loadFactor = Math.min(1.18, state.loadFactor + 0.2);
    return state;
}

function generate24(device, state) {
    const ratedV_LL = parseFloat(device.LRV);
    const ratedV_LN = ratedV_LL / Math.sqrt(3);
    const ratedI = device.LRA;
    const load = state.loadFactor;
    const imb = () => 1 + (Math.random() - 0.5) * 0.05;

    const V_A = ratedV_LN * (0.96 + Math.random() * 0.07) * imb();
    const V_B = ratedV_LN * (0.96 + Math.random() * 0.07) * imb();
    const V_C = ratedV_LN * (0.96 + Math.random() * 0.07) * imb();
    const overshoot = load > 1.0 ? 1.04 : 1.0;
    const V_AB = V_A * Math.sqrt(3) * imb() * overshoot;
    const V_BC = V_B * Math.sqrt(3) * imb() * overshoot;
    const V_AC = V_C * Math.sqrt(3) * imb() * overshoot;
    const I_A = ratedI * load * imb();
    const I_B = ratedI * load * imb();
    const I_C = ratedI * load * imb();
    const PF_A = 0.85 + Math.random() * 0.14;
    const PF_B = 0.85 + Math.random() * 0.14;
    const PF_C = 0.85 + Math.random() * 0.14;
    const P_A = V_A * I_A * PF_A;
    const P_B = V_B * I_B * PF_B;
    const P_C = V_C * I_C * PF_C;
    const S_A = V_A * I_A;
    const S_B = V_B * I_B;
    const S_C = V_C * I_C;
    const Q_A = Math.sqrt(Math.max(0, S_A * S_A - P_A * P_A));
    const Q_B = Math.sqrt(Math.max(0, S_B * S_B - P_B * P_B));
    const Q_C = Math.sqrt(Math.max(0, S_C * S_C - P_C * P_C));
    const VAngle_AB = 120 + (Math.random() - 0.5) * 2;
    const VAngle_BC = 120 + (Math.random() - 0.5) * 2;
    const VAngle_AC = 120 + (Math.random() - 0.5) * 2;

    return [
        V_A, V_B, V_C,
        V_AB, V_BC, V_AC,
        I_A, I_B, I_C,
        P_A, P_B, P_C,
        Q_A, Q_B, Q_C,
        S_A, S_B, S_C,
        PF_A, PF_B, PF_C,
        VAngle_AB, VAngle_BC, VAngle_AC,
    ];
}

for (let i = 0; i < devices.length; i++) {
    const device = devices[i];
    const stateKey = 'transformer_state_' + device.IMEI;
    let state = flow.get(stateKey) || initState();
    state = evolve(state);

    const data = generate24(device, state);
    // Approximate energy accumulation (kWh per tick)
    const P_total = data[9] + data[10] + data[11];
    state.netE += (P_total * 5) / (3600 * 1000);
    flow.set(stateKey, state);

    const PF_AVG = (data[18] + data[19] + data[20]) / 3;
    const F = 50 + (Math.random() - 0.5) * 0.2;
    const TS = Math.floor(Date.now() / 1000);

    // 3-element JSON array — matches the original SEDC MQTT payload
    node.send({
        payload: [
            { IMEI: device.IMEI, TS: String(TS), S_P_F: [PF_AVG, F] },
            { IMEI: device.IMEI, TS: String(TS), DATA: data },
            { IMEI: device.IMEI, TS: String(TS), Net_E: [state.netE] },
        ]
    });
}

return null;

// Faithful rebuild of the original SEDC Energy Readings decoder.
// Unpacks the 3-element JSON array into a single combined object
// containing header + data + alarm flags.

const env_data = env.get('Devices');
const devices = env_data.data;

const payload = msg.payload;
if (!Array.isArray(payload) || payload.length < 3) {
    node.warn('Invalid payload — expected 3-element array');
    return null;
}

const meta = payload[0];          // { IMEI, TS, S_P_F: [pf, f] }
const data_pkt = payload[1];      // { IMEI, TS, DATA: [24 values] }
const energy_pkt = payload[2];    // { IMEI, TS, Net_E: [kWh] }

const imei = meta.IMEI;
const device = devices.find(d => d.IMEI === imei);
if (!device) {
    node.warn('Unknown IMEI: ' + imei);
    return null;
}

const d = data_pkt.DATA;
const V_A = d[0], V_B = d[1], V_C = d[2];
const V_AB = d[3], V_BC = d[4], V_AC = d[5];
const I_A = d[6], I_B = d[7], I_C = d[8];
const P_A = d[9], P_B = d[10], P_C = d[11];
const Q_A = d[12], Q_B = d[13], Q_C = d[14];
const S_A = d[15], S_B = d[16], S_C = d[17];
const PF_A = d[18], PF_B = d[19], PF_C = d[20];
const VAngle_AB = d[21], VAngle_BC = d[22], VAngle_AC = d[23];

const V_AVG = (V_A + V_B + V_C) / 3;
const V2_AVG = (V_AB + V_BC + V_AC) / 3;
const I_AVG = (I_A + I_B + I_C) / 3;
const P_TOTAL = (P_A + P_B + P_C) / 3;
const Q_TOTAL = (Q_A + Q_B + Q_C) / 3;
const S_TOTAL = (S_A + S_B + S_C) / 3;
const VAngle_AVG = (VAngle_AB + VAngle_BC + VAngle_AC) / 3;

const V_AB_alarm = V_AB > device.V2_limit;
const V_BC_alarm = V_BC > device.V2_limit;
const V_AC_alarm = V_AC > device.V2_limit;
const I_A_alarm = I_A > device.I_limit;
const I_B_alarm = I_B > device.I_limit;
const I_C_alarm = I_C > device.I_limit;
const V_Alarm = V_AB_alarm || V_BC_alarm || V_AC_alarm;
const I_Alarm = I_A_alarm || I_B_alarm || I_C_alarm;

const Net_E = energy_pkt.Net_E[0];
const totalS_3ph = S_A + S_B + S_C;
const load_percent = (totalS_3ph / (device.rated_kva * 1000)) * 100;

const ts = parseInt(meta.TS, 10) * 1000;
const dt = new Date(ts);

msg.payload = {
    IMEI: imei,
    device: device.device,
    site_en: device.site_e,
    site_ar: device.site,
    address: device.address,
    lat: device.lat,
    long: device.long,
    LRV: device.LRV,
    LRA: device.LRA,
    RP: device.RP,
    rated_kva: device.rated_kva,
    I_limit: device.I_limit,
    V2_limit: device.V2_limit,
    DATE: dt.toISOString().slice(0, 10),
    TIME: dt.toTimeString().slice(0, 8),
    SPF: meta.S_P_F[0],
    F: meta.S_P_F[1],
    Net_E: Net_E,
    reading: {
        V_A, V_B, V_C, V_AB, V_BC, V_AC,
        I_A, I_B, I_C,
        P_A, P_B, P_C,
        Q_A, Q_B, Q_C,
        S_A, S_B, S_C,
        PF_A, PF_B, PF_C,
        VAngle_AB, VAngle_BC, VAngle_AC,
    },
    V_AVG, V2_AVG, I_AVG,
    P_TOTAL, Q_TOTAL, S_TOTAL,
    VAngle_AVG,
    load_percent,
    alarms: {
        V_AB_alarm, V_BC_alarm, V_AC_alarm,
        I_A_alarm, I_B_alarm, I_C_alarm,
        V_Alarm, I_Alarm,
        any: V_Alarm || I_Alarm,
    },
};

return msg;

// Reshape the decoder output into the TransformerUpdate shape
// the React dashboard expects.

const info = msg.payload;
const r = (n) => Math.round(n * 100) / 100;
const r4 = (n) => Math.round(n * 10000) / 10000;

msg.payload = {
    type: 'transformer_update',
    timestamp: new Date().toISOString(),
    imei: parseInt(info.IMEI, 10),
    device: info.device,
    site: {
        name_en: info.site_en,
        name_ar: info.site_ar,
        city: info.site_en.includes('Omdurman') ? 'Omdurman' : info.site_en.includes('Shambat') ? 'Khartoum North' : 'Khartoum',
        address: info.address,
        lat: info.lat,
        long: info.long,
    },
    spec: {
        LRV: info.LRV,
        LRA: info.LRA,
        RP: info.RP,
        rated_kva: info.rated_kva,
        I_limit: info.I_limit,
        V2_limit: info.V2_limit,
    },
    reading: {
        V_A: r(info.reading.V_A), V_B: r(info.reading.V_B), V_C: r(info.reading.V_C),
        V_AB: r(info.reading.V_AB), V_BC: r(info.reading.V_BC), V_AC: r(info.reading.V_AC),
        I_A: r(info.reading.I_A), I_B: r(info.reading.I_B), I_C: r(info.reading.I_C),
        P_A: r(info.reading.P_A), P_B: r(info.reading.P_B), P_C: r(info.reading.P_C),
        Q_A: r(info.reading.Q_A), Q_B: r(info.reading.Q_B), Q_C: r(info.reading.Q_C),
        S_A: r(info.reading.S_A), S_B: r(info.reading.S_B), S_C: r(info.reading.S_C),
        PF_A: r4(info.reading.PF_A), PF_B: r4(info.reading.PF_B), PF_C: r4(info.reading.PF_C),
        VAngle_AB: r(info.reading.VAngle_AB), VAngle_BC: r(info.reading.VAngle_BC), VAngle_AC: r(info.reading.VAngle_AC),
        V_AVG: r(info.V_AVG), V2_AVG: r(info.V2_AVG), I_AVG: r(info.I_AVG),
        P_TOTAL: r(info.P_TOTAL), Q_TOTAL: r(info.Q_TOTAL), S_TOTAL: r(info.S_TOTAL),
        VAngle_AVG: r(info.VAngle_AVG),
        SPF: r4(info.SPF),
        F: r(info.F),
        Net_E: r(info.Net_E),
        load_percent: r(info.load_percent),
    },
    alarms: info.alarms,
    rtc: info.TIME,
    date: info.DATE,
};

return msg;
